  -- =========================================================================
  -- STEP 0: Find admin user (3-level fallback)
  -- =========================================================================
  SELECT id INTO v_admin_id
  FROM user_profiles
  WHERE role = 'admin'
  ORDER BY created_at ASC
  LIMIT 1;

  IF v_admin_id IS NULL THEN
    SELECT id INTO v_admin_id
    FROM auth.users
    WHERE raw_user_meta_data->>'role' = 'admin'
    ORDER BY created_at ASC
    LIMIT 1;
  END IF;

  IF v_admin_id IS NULL THEN
    SELECT id INTO v_admin_id
    FROM auth.users
    ORDER BY created_at ASC
    LIMIT 1;
  END IF;

  IF v_admin_id IS NULL THEN
    RAISE NOTICE 'No users found — skipping admin panel seed data';
    RETURN;
